package com.example.formosaoilstation.navigation

import androidx.compose.foundation.layout.padding
import androidx.compose.material3.Icon
import androidx.compose.material3.NavigationBar
import androidx.compose.material3.NavigationBarItem
import androidx.compose.material3.Scaffold
import androidx.compose.material3.Text
import androidx.compose.runtime.Composable
import androidx.compose.runtime.getValue
import androidx.compose.ui.Modifier
import androidx.navigation.NavHostController
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import androidx.navigation.compose.currentBackStackEntryAsState
import androidx.navigation.compose.rememberNavController
import androidx.navigation.NavType\nimport androidx.navigation.navArgument\nimport com.example.formosaoilstation.map.MapScreen\nimport com.example.formosaoilstation.near.FavoriteScreen\nimport com.example.formosaoilstation.near.NearScreen\nimport com.example.formosaoilstation.near.StationDetailScreen\nimport com.example.formosaoilstation.price.PriceScreen\n\n@Composable\nfun MainScreen() {\n    val navController = rememberNavController()\n    Scaffold(\n        bottomBar = {\n            BottomNavigationBar(navController = navController)\n        }\n    ) { innerPadding ->\n        NavigationGraph(navController = navController, modifier = Modifier.padding(innerPadding))\n    }\n}\n\n@Composable\nfun BottomNavigationBar(navController: NavHostController) {\n    val items = listOf(\n        NavigationItem.Map,\n        NavigationItem.Favorite,\n        NavigationItem.Near,\n        NavigationItem.Price\n    )\n    NavigationBar {\n        val navBackStackEntry by navController.currentBackStackEntryAsState()\n        val currentRoute = navBackStackEntry?.destination?.route\n\n        val filteredItems = items.filter { it !is NavigationItem.StationDetail }\n\n        filteredItems.forEach { item ->\n            NavigationBarItem(\n                icon = { Icon(imageVector = item.icon, contentDescription = item.title) },\n                label = { Text(text = item.title) },\n                selected = currentRoute == item.route ||\n                           (item is NavigationItem.Favorite && currentRoute?.startsWith(NavigationItem.StationDetail.route.substringBefore(\"/\")) == true),\n                onClick = {\n                    navController.navigate(item.route) {\n                        navController.graph.startDestinationRoute?.let { route ->\n                            popUpTo(route) {\n                                saveState = true\n                            }\n                        }\n                        launchSingleTop = true\n                        restoreState = true\n                    }\n                }\n            )\n        }\n    }\n}\n\n@Composable\nfun NavigationGraph(navController: NavHostController, modifier: Modifier = Modifier) {\n    NavHost(navController, startDestination = NavigationItem.Map.route, modifier = modifier) {\n        composable(NavigationItem.Map.route) {\n            MapScreen()\n        }\n        composable(NavigationItem.Favorite.route) {\n            FavoriteScreen(onStationClick = { stationName ->\n                navController.navigate(NavigationItem.StationDetail.createRoute(stationName))\n            })\n        }\n        composable(NavigationItem.Near.route) {\n            NearScreen(onStationClick = { stationName ->\n                navController.navigate(NavigationItem.StationDetail.createRoute(stationName))\n            })\n        }\n        composable(NavigationItem.Price.route) {\n            PriceScreen()\n        }\n        composable(\n            route = NavigationItem.StationDetail.route,\n            arguments = listOf(navArgument(\"stationName\") { type = NavType.StringType })\n        ) {\ backStackEntry ->\n            val stationName = backStackEntry.arguments?.getString(\"stationName\")\n            if (stationName != null) {\n                // StationDetailScreen will fetch the Feature from ViewModel\n                StationDetailScreenWrapper(stationName = stationName)\n            }\n        }\n    }\n}\n\n@Composable\nfun StationDetailScreenWrapper(stationName: String, viewModel: NearViewModel = viewModel()) {\n    val stations by viewModel.stations.collectAsState()\n    val feature = remember(stations, stationName) {\n        stations.find { it.properties?.name == stationName }\n    }\n    if (feature != null) {\n        StationDetailScreen(feature = feature)\n    } else {\n        Text(\"Station not found\")\n    }\n}\n
